import React, { useState, useEffect } from 'react';
import { api } from '../api';
import { useAuth } from '../contexts/AuthContext';

export default function ProductsPage() {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [editingProduct, setEditingProduct] = useState(null);
  const [formData, setFormData] = useState({
    title: '',
    category: '',
    description: '',
    price: ''
  });
  const { isSeller, isAdmin } = useAuth();

  useEffect(() => {
    loadProducts();
  }, []);

  const loadProducts = async () => {
    try {
      setLoading(true);
      const response = await api.getProducts();
      setProducts(response.data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Удалить товар?')) return;
    try {
      await api.deleteProduct(id);
      setProducts(products.filter(p => p.id !== id));
    } catch (err) {
      alert('Ошибка удаления');
    }
  };

  const openCreate = () => {
    setEditingProduct(null);
    setFormData({ title: '', category: '', description: '', price: '' });
    setShowForm(true);
  };

  const openEdit = (product) => {
    setEditingProduct(product);
    setFormData({
      title: product.title,
      category: product.category,
      description: product.description,
      price: product.price
    });
    setShowForm(true);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editingProduct) {
        const response = await api.updateProduct(editingProduct.id, formData);
        setProducts(products.map(p => p.id === editingProduct.id ? response.data : p));
      } else {
        const response = await api.createProduct(formData);
        setProducts([...products, response.data]);
      }
      setShowForm(false);
    } catch (err) {
      alert('Ошибка сохранения');
    }
  };

  if (loading) return <div style={styles.loading}>Загрузка...</div>;

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h2>📦 Товары</h2>
        {isSeller && (
          <button onClick={openCreate} style={styles.addButton}>+ Добавить товар</button>
        )}
      </div>

      <div style={styles.grid}>
        {products.map(product => (
          <div key={product.id} style={styles.card}>
            <h3>{product.title}</h3>
            <p style={styles.category}>{product.category}</p>
            <p>{product.description}</p>
            <div style={styles.row}>
              <span style={styles.price}>{product.price} ₽</span>
            </div>
            {(isSeller || isAdmin) && (
              <div style={styles.actions}>
                <button onClick={() => openEdit(product)} style={styles.editBtn}>✏️</button>
                {isAdmin && (
                  <button onClick={() => handleDelete(product.id)} style={styles.deleteBtn}>🗑️</button>
                )}
              </div>
            )}
          </div>
        ))}
      </div>

      {showForm && (
        <div style={styles.modal}>
          <div style={styles.modalContent}>
            <h3>{editingProduct ? 'Редактировать' : 'Новый товар'}</h3>
            <form onSubmit={handleSubmit}>
              <input
                placeholder="Название"
                value={formData.title}
                onChange={(e) => setFormData({...formData, title: e.target.value})}
                style={styles.input}
                required
              />
              <input
                placeholder="Категория"
                value={formData.category}
                onChange={(e) => setFormData({...formData, category: e.target.value})}
                style={styles.input}
                required
              />
              <textarea
                placeholder="Описание"
                value={formData.description}
                onChange={(e) => setFormData({...formData, description: e.target.value})}
                style={styles.input}
                required
              />
              <input
                type="number"
                placeholder="Цена"
                value={formData.price}
                onChange={(e) => setFormData({...formData, price: e.target.value})}
                style={styles.input}
                required
              />
              <div style={styles.modalActions}>
                <button type="submit" style={styles.saveBtn}>Сохранить</button>
                <button type="button" onClick={() => setShowForm(false)} style={styles.cancelBtn}>Отмена</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

const styles = {
  container: { padding: '20px', maxWidth: '1200px', margin: '0 auto' },
  header: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' },
  addButton: { background: '#4ade80', color: '#0b0f19', border: 'none', padding: '10px 20px', borderRadius: '8px', cursor: 'pointer' },
  grid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '20px' },
  card: { background: '#1a1f2e', padding: '15px', borderRadius: '12px' },
  category: { color: '#888', fontSize: '14px' },
  price: { color: '#4ade80', fontSize: '20px', fontWeight: 'bold' },
  row: { display: 'flex', justifyContent: 'space-between', margin: '10px 0' },
  actions: { display: 'flex', gap: '10px', marginTop: '10px' },
  editBtn: { background: '#4a90e2', color: 'white', border: 'none', padding: '5px 10px', borderRadius: '4px', cursor: 'pointer' },
  deleteBtn: { background: '#e24a4a', color: 'white', border: 'none', padding: '5px 10px', borderRadius: '4px', cursor: 'pointer' },
  loading: { textAlign: 'center', padding: '40px', color: '#888' },
  modal: { position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, background: 'rgba(0,0,0,0.7)', display: 'flex', alignItems: 'center', justifyContent: 'center' },
  modalContent: { background: '#1a1f2e', padding: '20px', borderRadius: '12px', width: '90%', maxWidth: '500px' },
  input: { width: '100%', padding: '10px', margin: '10px 0', background: '#2a2f3e', border: '1px solid #333', color: 'white', borderRadius: '6px' },
  modalActions: { display: 'flex', gap: '10px', marginTop: '20px' },
  saveBtn: { flex: 1, padding: '10px', background: '#4ade80', color: '#0b0f19', border: 'none', borderRadius: '6px', cursor: 'pointer' },
  cancelBtn: { flex: 1, padding: '10px', background: '#666', color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer' }
};
